mapper.select:
SELECT m.member_id AS memberId, m.login_id AS loginId, m2.nickname, TO_CHAR(o.order_date, 'YYYY-MM') AS settlementMonth, COUNT(DISTINCT p.place_id) AS placeCount,
/* 총 결제액 : 결제완료 + 체크아웃완료 주문만 */ NVL(SUM(o.real_total_amount), 0) AS totalGmv,
/* 수수료 : 숙소별 commission_rate × 결제액 */ NVL(SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)), 0) AS totalCommission,
/* 쿠폰 파트너 부담액 합계 */ NVL(SUM(cu.partner_discount_amount), 0) AS totalCouponPartner,
/* 최종 지급액 */ NVL(SUM(o.real_total_amount) - SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)) - SUM(NVL(cu.partner_discount_amount, 0)), 0) AS totalNetPayout,
/* 대표 지역 */ MIN(p.region) AS region,
/* 정산 상태 집계 */ CASE WHEN COUNT(DISTINCT p.place_id) = SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END) THEN 'DONE' WHEN SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END) > 0 THEN 'PARTIAL' ELSE 'PENDING' END AS settlementStatus,
SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END) AS approvedPlaceCount
FROM member1 m JOIN member2 m2 ON m.member_id = m2.member_id JOIN place p ON p.partner_id = m.member_id JOIN orders o ON o.place_id = p.place_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = m.member_id LEFT JOIN settlement stl ON stl.place_id = p.place_id AND TO_CHAR(stl.settlement_month, 'YYYY-MM') = TO_CHAR(o.order_date, 'YYYY-MM') WHERE m.role = 'ROLE_PARTNER' AND o.status IN ('결제완료', '체크아웃완료')
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
AND (
COUNT(DISTINCT p.place_id) = SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END)
SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END) > 0 AND COUNT(DISTINCT p.place_id) > SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END)
SUM(CASE WHEN stl.status = 'APPROVED' THEN 1 ELSE 0 END) = 0
)
AND (m.login_id LIKE '%' || #{keyword} || '%' OR m2.nickname LIKE '%' || #{keyword} || '%')
AND p.region = #{region}
GROUP BY m.member_id, m.login_id, m2.nickname, TO_CHAR(o.order_date, 'YYYY-MM') ORDER BY settlementMonth DESC, totalGmv DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM ( SELECT m.member_id FROM member1 m JOIN member2 m2 ON m.member_id = m2.member_id JOIN place p ON p.partner_id = m.member_id JOIN orders o ON o.place_id = p.place_id WHERE m.role = 'ROLE_PARTNER' AND o.status IN ('결제완료', '체크아웃완료')
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
AND (m.login_id LIKE '%' || #{keyword} || '%' OR m2.nickname LIKE '%' || #{keyword} || '%')
AND p.region = #{region}
GROUP BY m.member_id, TO_CHAR(o.order_date, 'YYYY-MM') )

SELECT o.order_id, od.reservation_id, o.order_date, m2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM orders o JOIN order_detail od ON od.order_id = o.order_id JOIN member1 m ON m.member_id = o.member_id JOIN member2 m2 ON m2.member_id = m.member_id JOIN place p ON p.place_id = o.place_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.partner_id = #{memberId} AND o.status IN ('결제완료', '체크아웃완료')
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY p.place_id, o.order_date DESC

SELECT o.order_id, od.reservation_id, o.order_date, m2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM orders o JOIN order_detail od ON od.order_id = o.order_id JOIN member1 m ON m.member_id = o.member_id JOIN member2 m2 ON m2.member_id = m.member_id JOIN place p ON p.place_id = o.place_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.place_id = #{placeId} AND o.status IN ('결제완료', '체크아웃완료')
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY o.order_date DESC
